#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <math.h>

double parseExpression(char *s);
double parseTerm(char *s);
double parseFactor(char *s);
double parseNumber(char *s);

double parseNumber(char *s) {
    char buf[64];
    int i = 0;
    while (isdigit(*s) || *s == '.') {
        buf[i++] = *s++;
    }
    buf[i] = '\0';
    return strtod(buf, NULL);
}

double parseFactor(char *s) {
    while (isspace(*s)) s++;
    if (strncmp(s, "int", 3) == 0) {
        s += 3; while (isspace(*s)) s++;
        if (*s == '(') { s++; double val = parseExpression(s); while (isspace(*s)) s++;
            if (*s == ')') s++; return (double)((int)val); }
    }
    if (strncmp(s, "float", 5) == 0) {
        s += 5; while (isspace(*s)) s++;
        if (*s == '(') { s++; double val = parseExpression(s); while (isspace(*s)) s++;
            if (*s == ')') s++; return val; }
    }
    if (*s == '(') {
        s++; double val = parseExpression(s); while (isspace(*s)) s++;
        if (*s == ')') s++; return val;
    }
    return parseNumber(s);
}

double parseTerm(char *s) {
    double val = parseFactor(s);
    while (1) {
        while (isspace(*s)) s++;
        if (*s == '*') { s++; val *= parseFactor(s); }
        else if (*s == '/') { s++; val /= parseFactor(s); }
        else break;
    }
    return val;
}

double parseExpression(char *s) {
    double val = parseTerm(s);
    while (1) {
        while (isspace(*s)) s++;
        if (*s == '+') { s++; val += parseTerm(s); }
        else if (*s == '-') { s++; val -= parseTerm(s); }
        else break;
    }
    return val;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar();
    char line[128];
    while (T--) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0';
        double result = parseExpression(line);
        if (fabs(result - round(result)) < 1e-9) {
            printf("%d\n", (int)round(result));
        } else {
            printf("%g\n", result);
        }
    }
    return 0;
}

