    void skip() { while (pos < str->size() && isspace((*str)[pos])) ++pos; }
    double parseExpression();
    double parseTerm();
    double parseFactor();
    double parseNumber() {
        skip();
        size_t start = pos;
        while (pos < str->size() && (isdigit((*str)[pos]) || (*str)[pos]=='.')) ++pos;
        return stod(str->substr(start, pos-start));
    }
};

double Parser::parseFactor() {
    skip();
    if (str->compare(pos, 3, "int") == 0) {
        pos += 3; skip(); if (pos < str->size() && (*str)[pos]=='(') { ++pos; double v = parseExpression(); skip(); if (pos < str->size() && (*str)[pos]==')') ++pos; return (double)((int)v); }
    }
    if (str->compare(pos, 5, "float") == 0) {
        pos += 5; skip(); if (pos < str->size() && (*str)[pos]=='(') { ++pos; double v = parseExpression(); skip(); if (pos < str->size() && (*str)[pos]==')') ++pos; return v; }
    }
    if (pos < str->size() && (*str)[pos]=='(') {
        ++pos; double v = parseExpression(); skip(); if (pos < str->size() && (*str)[pos]==')') ++pos; return v;
    }
    return parseNumber();
}

double Parser::parseTerm() {
    double v = parseFactor();
    while (true) {
        skip();
        if (pos < str->size() && (*str)[pos]=='*') { ++pos; v *= parseFactor(); }
        else if (pos < str->size() && (*str)[pos]=='/') { ++pos; v /= parseFactor(); }
        else break;
    }
    return v;
}

double Parser::parseExpression() {
    double v = parseTerm();
    while (true) {
        skip();
        if (pos < str->size() && (*str)[pos]=='+') { ++pos; v += parseTerm(); }
        else if (pos < str->size() && (*str)[pos]=='-') { ++pos; v -= parseTerm(); }
        else break;
    }
    return v;
}

