        double parseFactor(){skip();if(s.startsWith("int",pos)){pos+=3;skip();if(pos<s.length() && s.charAt(pos)=='('){pos++;double v=parseExpression();skip();if(pos<s.length() && s.charAt(pos)==')')pos++;return (double)((int)v);} }
            if(s.startsWith("float",pos)){pos+=5;skip();if(pos<s.length() && s.charAt(pos)=='('){pos++;double v=parseExpression();skip();if(pos<s.length() && s.charAt(pos)==')')pos++;return v;} }
