  function parseFactor(){skip(); if(expr.startsWith('int',pos)) {pos+=3; skip(); if(expr[pos]==='('){pos++; let v=parseExpression(); skip(); if(expr[pos]===')') pos++; return Math.trunc(v);} }
    if(expr.startsWith('float',pos)) {pos+=5; skip(); if(expr[pos]==='('){pos++; let v=parseExpression(); skip(); if(expr[pos]===')') pos++; return v;} }
    if(expr[pos]==='('){pos++; let v=parseExpression(); skip(); if(expr[pos]===')') pos++; return v; }
