  function parseTerm(){ let v=parseFactor(); while(true){ skip(); if(expr[pos]==='*'){pos++; v*=parseFactor();} else if(expr[pos]==='/'){pos++; v/=parseFactor();} else break; } return v; }
  function parseExpression(){ let v=parseTerm(); while(true){ skip(); if(expr[pos]==='+'){pos++; v+=parseTerm();} else if(expr[pos]==='-'){pos++; v-=parseTerm();} else break; } return v; }
